//   GstMemory *memory;
//   gint size, width, height, bpp;
//   ...
//   size = width * height * bpp;
//   buffer = gst_buffer_new ();
//   memory = gst_allocator_alloc (NULL, size, NULL);
//   gst_buffer_insert_memory (buffer, -1, memory);
