func UnsafeStructureFromGlibFull(p unsafe.Pointer) *Structure {
	wrapped := UnsafeStructureFromGlibBorrow(p)
	runtime.SetFinalizer(
		wrapped.structure,
		func (intern *structure) {
			C.gst_structure_free(intern.native)
		},
	)
	return wrapped
}

